{
  "domain_analysis": {
    "business_context": "Order cancellation in a logistics/courier platform. Cancellation is one of the most operationally sensitive features because an order passes through multiple lifecycle stages — each involving increasing real-world cost commitments (driver dispatch, pickup, in-transit). The cancellation window and its consequences change dramatically depending on fulfillment state.",
    "bounded_context": "Order Management",
    "ubiquitous_language": [
      { "term": "Order", "definition": "A request from a user for courier pickup and delivery of a package, progressing through a defined lifecycle of states." },
      { "term": "Cancellation", "definition": "A user-initiated request to abort an order, reversing any uncommitted work and triggering appropriate compensation for committed work." },
      { "term": "Order State", "definition": "The current lifecycle phase of an order (e.g., Pending, Confirmed, Assigned, Picked Up, In Transit, Delivered, Cancelled)." },
      { "term": "Cancellation Window", "definition": "The set of order states during which cancellation is permitted. Once the window closes, cancellation is no longer possible through self-service." },
      { "term": "Cancellation Fee", "definition": "A charge applied to the user when cancellation occurs after real-world costs have been incurred (e.g., a courier has already been dispatched)." },
      { "term": "Refund", "definition": "The return of payment to the user upon cancellation, potentially reduced by any applicable cancellation fee." },
      { "term": "Courier Assignment", "definition": "The point at which a driver/courier has been dispatched or committed to fulfill the order — a key inflection point for cancellation cost." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "An order may only be cancelled when it is in a cancellable state. Cancellable states are: Pending, Confirmed, Assigned. Orders in Picked Up, In Transit, or Delivered states are NOT cancellable via self-service.",
      "invariant": true,
      "invariant_justification": "Once a courier physically possesses the package (Picked Up or later), the user cannot unilaterally reverse the real-world action. Allowing cancellation of a delivered order would corrupt system state and financial records.",
      "testable_assertion": "Given an order in state Picked Up, In Transit, or Delivered, when a cancellation request is submitted, then the system MUST reject it with an appropriate error."
    },
    {
      "id": "BR-2",
      "rule": "A cancelled order's state must transition to 'Cancelled' and this transition is terminal — a cancelled order cannot be reactivated or move to any other state.",
      "invariant": true,
      "invariant_justification": "Cancelled is a terminal state. Allowing resurrection of cancelled orders would break financial reconciliation, audit trails, and potentially double-dispatch couriers.",
      "testable_assertion": "Given an order in state Cancelled, when any state transition is attempted, then the system MUST reject it."
    },
    {
      "id": "BR-3",
      "rule": "Only the user who placed the order (the order owner) may cancel it. Support agents may cancel on behalf of users through a separate privileged flow.",
      "invariant": true,
      "invariant_justification": "Allowing arbitrary users to cancel others' orders is a data integrity and authorization violation.",
      "testable_assertion": "Given a cancellation request from a user who is NOT the order owner, when the request is processed, then the system MUST reject it with a 403/Forbidden."
    },
    {
      "id": "BR-4",
      "rule": "If a courier has already been assigned (state = Assigned), a cancellation fee MAY be applied per the current fee policy. The fee amount and whether it applies is a configurable business policy.",
      "invariant": false,
      "invariant_justification": "The fee amount and applicability are business policy decisions that may change. A VP could decide to waive fees during a promotional period.",
      "testable_assertion": "Given an order in state Assigned, when cancellation is processed, then the system MUST evaluate the cancellation fee policy and apply or waive fees accordingly."
    },
    {
      "id": "BR-5",
      "rule": "A refund must be issued for any payment collected, minus any applicable cancellation fee. The refund must be processed through the original payment method.",
      "invariant": false,
      "invariant_justification": "Refund policy and method are business decisions that could be adjusted (e.g., store credit vs original method). The obligation to return money is strong but the mechanism is policy.",
      "testable_assertion": "Given a cancelled order with payment collected, when the cancellation is finalized, then a refund record MUST be created for (payment amount - cancellation fee) against the original payment method."
    },
    {
      "id": "BR-6",
      "rule": "When an order with an assigned courier is cancelled, the courier MUST be notified and unassigned so they are returned to the available pool.",
      "invariant": true,
      "invariant_justification": "Failing to release the courier leaves them in a ghost assignment — they believe they have a job that no longer exists. This corrupts dispatch state and wastes courier time, directly harming operations.",
      "testable_assertion": "Given an order in state Assigned that is cancelled, when cancellation completes, then the courier assignment MUST be released AND a notification event MUST be emitted to the courier."
    },
    {
      "id": "BR-7",
      "rule": "Every cancellation MUST be recorded with a timestamp, the initiating user, the order state at time of cancellation, and an optional reason. This record is immutable.",
      "invariant": true,
      "invariant_justification": "Audit trail integrity. Cancellation records are needed for financial reconciliation, dispute resolution, and fraud detection. Mutating or omitting them corrupts the business record.",
      "testable_assertion": "Given any successful cancellation, when the cancellation is persisted, then an immutable cancellation record MUST exist containing: timestamp, user_id, prior_order_state, and reason (nullable)."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "An order in state Pending or Confirmed with no courier assigned",
      "when": "The order owner requests cancellation",
      "then": "The order transitions to Cancelled, a full refund is issued, and a cancellation audit record is created"
    },
    {
      "id": "AC-2",
      "given": "An order in state Assigned (courier dispatched but package not yet picked up)",
      "when": "The order owner requests cancellation",
      "then": "The order transitions to Cancelled, the courier is unassigned and notified, a refund minus any applicable cancellation fee is issued, and a cancellation audit record is created"
    },
    {
      "id": "AC-3",
      "given": "An order in state Picked Up or In Transit",
      "when": "The order owner requests cancellation",
      "then": "The cancellation is rejected with a clear message explaining the order is no longer cancellable and directing the user to contact support"
    },
    {
      "id": "AC-4",
      "given": "An order in state Delivered",
      "when": "The order owner requests cancellation",
      "then": "The cancellation is rejected with a clear message that delivered orders cannot be cancelled"
    },
    {
      "id": "AC-5",
      "given": "An order in state Cancelled",
      "when": "Any further state transition is attempted (including a second cancellation)",
      "then": "The request is rejected; the order remains in Cancelled state and no duplicate refund or event is generated"
    },
    {
      "id": "AC-6",
      "given": "A user who is NOT the order owner",
      "when": "They attempt to cancel the order",
      "then": "The request is rejected with a 403 Forbidden; no state change occurs"
    },
    {
      "id": "AC-7",
      "given": "Two simultaneous cancellation requests for the same order (race condition)",
      "when": "Both requests are processed concurrently",
      "then": "Exactly one cancellation succeeds; the second receives a conflict or already-cancelled response. Exactly one refund is issued. Exactly one audit record is created."
    },
    {
      "id": "AC-8",
      "given": "An order in state Confirmed that transitions to Assigned between the user viewing the cancel button and submitting the cancellation",
      "when": "The cancellation request arrives and the order is now Assigned",
      "then": "The cancellation still succeeds (Assigned is cancellable) but the cancellation fee policy is evaluated against the current state at processing time, NOT the stale state the user saw"
    },
    {
      "id": "AC-9",
      "given": "An order in state Assigned that transitions to Picked Up between the user initiating cancellation and the server processing it",
      "when": "The cancellation request arrives and the order is now Picked Up",
      "then": "The cancellation is rejected because the order is no longer in a cancellable state; the user is informed the order has progressed"
    },
    {
      "id": "AC-10",
      "given": "A cancellation is processed but the refund service is temporarily unavailable",
      "when": "The refund call fails",
      "then": "The order is still marked Cancelled (cancellation is not rolled back), but the refund is queued for retry. The user is informed their refund is being processed."
    }
  ],

  "edge_cases": [
    {
      "scenario": "Double-cancel: User clicks cancel twice in rapid succession",
      "expected_behavior": "Idempotent handling — the second request returns success or 'already cancelled' but does NOT trigger a duplicate refund or duplicate courier notification."
    },
    {
      "scenario": "State race: Order transitions from Assigned → Picked Up while cancellation request is in flight",
      "expected_behavior": "Cancellation must be evaluated against the order's state at write-time (optimistic locking or state check within transaction), not the state at read-time. Rejection if no longer cancellable."
    },
    {
      "scenario": "Partial payment: Order was paid with multiple payment methods (e.g., wallet + card)",
      "expected_behavior": "Refund must be distributed across original payment methods proportionally or per refund policy. Cannot refund more than was charged to any single method."
    },
    {
      "scenario": "Free/zero-cost order (promotional or comped)",
      "expected_behavior": "Cancellation proceeds normally. No refund is issued (amount = 0). No cancellation fee is charged. Audit record is still created."
    },
    {
      "scenario": "Courier has already incurred real costs (fuel, tolls) en route to pickup but package not yet picked up",
      "expected_behavior": "The cancellation fee policy should account for this. The order is still in Assigned state and therefore cancellable, but the fee may compensate for courier costs. The courier must be notified immediately."
    },
    {
      "scenario": "Network failure after order state is set to Cancelled but before refund is initiated",
      "expected_behavior": "The system must not leave the user without a refund. A background reconciliation process must detect cancelled orders with missing refunds and retry. The cancellation itself is NOT rolled back."
    },
    {
      "scenario": "User cancels an order then immediately places a new identical order",
      "expected_behavior": "These are treated as two independent orders. The new order gets a new ID, fresh lifecycle. No state leakage from the cancelled order."
    },
    {
      "scenario": "Bulk cancellation: User has multiple orders and wants to cancel all of them",
      "expected_behavior": "Each order is evaluated independently. Some may be cancellable and others not. Partial success is acceptable — the user is informed which orders were cancelled and which were not, with reasons."
    }
  ],

  "business_impact": {
    "financial": "Cancellation directly impacts revenue (refunds), courier compensation (wasted dispatch), and potential cancellation fee income. Poor cancellation UX or overly restrictive policies lead to chargebacks and customer churn, which cost more than refunds. Missing cancellation fees on post-assignment cancels leaks margin.",
    "operational": "Courier pool utilization is directly affected — every post-assignment cancellation wastes a dispatch cycle. If courier release is unreliable (BR-6 violation), the dispatch system degrades over time with ghost assignments. Refund reconciliation failures create support ticket volume.",
    "user": "Cancellation is a trust signal. Users who can easily cancel feel safer placing orders. Opaque or broken cancellation erodes trust and increases support contacts. Clear communication about cancellation windows and fees is critical for user satisfaction.",
    "risk": "Primary risks: (1) Double-refund from race conditions causing financial loss, (2) Ghost courier assignments degrading dispatch reliability, (3) Missing audit records creating compliance exposure, (4) Stale-state cancellations allowing cancellation of in-transit orders. All are mitigatable with proper concurrency controls.",
    "stakeholders_affected": [
      { "group": "End Users (Senders)", "impact": "Gain self-service cancellation ability, improving autonomy and trust. Must understand cancellation windows and fee implications clearly." },
      { "group": "Couriers/Drivers", "impact": "Will receive cancellation notifications for assigned orders. Wasted trips affect earnings and morale — cancellation fee policy partially compensates." },
      { "group": "Customer Support", "impact": "Reduced ticket volume for cancellable-state orders. Will handle escalations for non-cancellable orders where users want exceptions." },
      { "group": "Finance/Accounting", "impact": "Must reconcile refunds and cancellation fees. Audit trail (BR-7) is critical for their processes." },
      { "group": "Dispatch/Operations", "impact": "Must handle courier release events. Unreliable cancellation flows directly impact dispatch efficiency." }
    ]
  },

  "confidence": {
    "level": 40,
    "reasoning": "The spec is a single sentence with no details on order states, cancellation windows, fee policy, refund rules, or authorization model. All business rules above are inferred from standard logistics domain knowledge, NOT from an explicit specification. Multiple critical decisions (which states are cancellable, fee amounts, refund method) are assumptions that MUST be confirmed with the product manager before implementation.",
    "high_confidence_areas": [
      "Cancelled is a terminal state (universal domain truth)",
      "Authorization: only order owner can cancel (standard access control)",
      "Courier must be released on cancellation of assigned order (operational necessity)",
      "Audit trail is required (standard for financial operations)",
      "Concurrency must be handled (race conditions are a physical reality)"
    ],
    "low_confidence_areas": [
      "Exact set of cancellable states — does the PM want Picked Up to be cancellable with a higher fee?",
      "Cancellation fee amounts and thresholds — no policy specified",
      "Refund method — original payment method vs store credit vs user choice",
      "Whether a cancellation reason is required or optional",
      "Whether there is a time-based cancellation window (e.g., free cancel within 5 minutes) vs purely state-based",
      "Bulk cancellation support — not mentioned, assumed out of scope"
    ],
    "assumptions": [
      "The order lifecycle includes states: Pending → Confirmed → Assigned → Picked Up → In Transit → Delivered",
      "Payment is collected before or at order confirmation",
      "Cancellation window is state-based, not time-based",
      "Cancellation fee only applies post-courier-assignment",
      "Self-service cancellation only — support escalation is a separate flow",
      "No partial cancellation (cancel entire order, not individual items)"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define which order states are cancellable. In logistics, the key inflection point is physical possession of the package. Should cancellation be allowed after courier pickup with a higher fee, or is pickup the hard cutoff?",
      "affected_stakeholders": ["End Users", "Couriers", "Customer Support"],
      "options": [
        "A: State-based cutoff at Picked Up (cancel allowed up to Assigned, rejected from Picked Up onward)",
        "B: Allow cancellation through In Transit with escalating fees, requiring courier to return/abandon package",
        "C: Time-based window (e.g., free cancel within N minutes regardless of state)"
      ],
      "recommendation": "Option A — cleanest operational boundary. Physical possession is an unambiguous, auditable event. Post-pickup cancellation creates complex reverse logistics that should be handled as a separate 'return' flow."
    },
    {
      "type": "ambiguity",
      "description": "No cancellation fee policy is defined. What are the fee amounts? Is it a flat fee, percentage, or dynamic based on courier distance traveled?",
      "affected_stakeholders": ["End Users", "Couriers", "Finance"],
      "options": [
        "A: No fee for any cancellation (simplest, but couriers absorb cost)",
        "B: Flat fee after courier assignment",
        "C: Dynamic fee based on courier's distance traveled or time elapsed"
      ],
      "recommendation": "Option B for MVP — flat fee is simplest to implement and communicate to users. Dynamic fees can be added later."
    },
    {
      "type": "missing_context",
      "description": "No information about the existing order state machine, payment model, or whether this is a new system or being added to an existing codebase. Need to understand current order lifecycle to define correct state transitions.",
      "affected_stakeholders": ["Engineering", "Product"],
      "options": [
        "Provide the current order entity schema and state machine",
        "Provide the existing payment/refund integration details"
      ],
      "recommendation": "Share the current order model and state definitions so acceptance criteria can reference actual states rather than assumed ones."
    }
  ],

  "rejection_reasons": []
}

